#include <stdio.h>
#include <stdlib.h>
#include <math.h>

typedef struct { float x, y, z; } V;
typedef struct { float t; V point, normal; int hit; } Hit;

static V vsub(V a, V b){ V r={a.x-b.x, a.y-b.y, a.z-b.z}; return r; }
static float vdot(V a, V b){ return (a.x*b.x + a.y*b.y) + a.z*b.z; }
static V vnorm(V v){ float l=sqrtf((v.x*v.x+v.y*v.y)+v.z*v.z); V r={v.x/l, v.y/l, v.z/l}; return r; }
static V vmul(V v, float s){ V r={v.x*s, v.y*s, v.z*s}; return r; }

static Hit sphere_intersect(V ro, V rd, V center, float radius){
    Hit h; h.hit=0; h.t=0; h.point.x=h.point.y=h.point.z=0; h.normal.x=h.normal.y=h.normal.z=0;
    V oc = vsub(ro, center);
    float a = vdot(rd, rd);
    float b = 2.0f*vdot(oc, rd);
    float c = vdot(oc, oc) - radius*radius;
    float disc = b*b - 4.0f*a*c;
    if(disc < 0.0f) return h;
    float t = (-b - sqrt(disc)) / (2.0f*a);
    if(t < 0.001f){
        t = (-b + sqrt(disc)) / (2.0f*a);
        if(t < 0.001f) return h;
    }
    h.t = t;
    V p = { ro.x+rd.x*t, ro.y+rd.y*t, ro.z+rd.z*t };
    h.point = p;
    h.normal = vnorm(vsub(p, center));
    h.hit = 1;
    return h;
}

static V sky_color(V dir){
    float t = 0.5f*(dir.y + 1.0f);
    float mt = 1.0f - t;
    V r = { t*0.5f + mt, t*0.7f + mt, mt + t };
    return r;
}

static V trace(V ro, V rd, V center, float radius, V light){
    Hit s = sphere_intersect(ro, rd, center, radius);
    int usePlane = 0;
    float tp = 0.0f;
    if(fabsf(rd.y) >= 1e-4f){
        tp = (-1.5f - ro.y) / rd.y;
        if(tp >= 0.001f) usePlane = 1;
    }
    int obj;
    if(s.hit && usePlane) obj = (s.t < tp) ? 0 : 1;
    else if(s.hit) obj = 0;
    else if(usePlane) obj = 1;
    else return sky_color(rd);

    V point, normal;
    if(obj == 0){ point = s.point; normal = s.normal; }
    else { V p={ ro.x+rd.x*tp, ro.y+rd.y*tp, ro.z+rd.z*tp }; point=p; normal.x=0.0f; normal.y=1.0f; normal.z=0.0f; }

    Hit sh = sphere_intersect(point, vnorm(light), center, radius);
    float inten;
    if(sh.hit) inten = 0.2f;
    else inten = 0.2f + 0.8f * (float)fmax(0.0, (double)vdot(normal, light));

    if(obj == 0){
        V base = { 1.0f, 0.2f, 0.2f };
        return vmul(base, inten);
    } else {
        int ch = (int)((double)floorf(point.x) + (double)floorf(point.z));
        float col = (ch & 1) ? 0.4f : 0.9f;
        V g = { col, col, col };
        return vmul(g, inten);
    }
}

static V **allocate_image(int width, int height){
    V **img = malloc(height * sizeof(V*));
    for(int i=0;i<height;i++) img[i] = malloc(width * sizeof(V));
    return img;
}
static void free_image(V **img, int height){
    for(int i=0;i<height;i++) free(img[i]);
    free(img);
}
static void write_image(const char *fn, V **img, int width, int height){
    FILE *f = fopen(fn, "w");
    if(!f) return;
    fprintf(f, "P3\n%d %d\n255\n", width, height);
    for(int y=0;y<height;y++){
        for(int x=0;x<width;x++){
            V c = img[y][x];
            int r = (int)((float)fmin(fmax((double)c.x,0.0),1.0) * 255.99f);
            int g = (int)((float)fmin(fmax((double)c.y,0.0),1.0) * 255.99f);
            int b = (int)((float)fmin(fmax((double)c.z,0.0),1.0) * 255.99f);
            fprintf(f, "%d %d %d\n", r, g, b);
        }
    }
    fclose(f);
    fprintf(stderr, "Wrote image to %s\n", fn);
}

int main(void){
    int width = 800, height = 600;
    fprintf(stderr, "Creating high-resolution image: %dx%d\n", width, height);
    fprintf(stderr, "This will be downsampled with ffmpeg after rendering\n");
    V light = vnorm((V){ 1.0f, 1.0f, -1.0f });
    V center = { 0.0f, -0.5f, -5.0f };
    float radius = 1.0f;
    float aspect = (float)width / (float)height;
    V **img = allocate_image(width, height);
    fprintf(stderr, "Rendering high-resolution image...\n");
    for(int y=0;y<height;y++){
        fprintf(stderr, "\rProgress: %.1f%%", 100.0f*y/600.0f);
        float vval = 2.0f*(1.0f - (float)y/599.0f);
        for(int x=0;x<width;x++){
            float u = (float)x/799.0f;
            V d;
            d.x = u*(2.0f*aspect) - aspect;
            d.y = vval - 1.0f;
            d.z = -1.0f;
            V ro = { 0.0f, 0.0f, 0.0f };
            V rd = vnorm(d);
            img[y][x] = trace(ro, rd, center, radius, light);
        }
    }
    fprintf(stderr, "\nRendering complete\n");
    write_image("image.ppm", img, width, height);
    free_image(img, height);
    fprintf(stderr, "Done.\n");
    return 0;
}

